  ('medical-tech-moex-20759', 'medical-tech', 'medical-tech-moex-093-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關第七凝血因子缺乏之實驗室檢查，下列何者正確？ 凝血 原時間（Prothrombin time）正常 凝血 時間（Thrombin time）延長 出血時間（Bleeding time）延長 病人血漿與久置之血漿（aged plasma）混和後，原延長之凝血 原時間（Prothrombin time）可恢復正常', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "33d4b0cf0707", "answer_pdf_sha1": "2b394db97a23", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
